const filename = $json.fileName;
const accountId = filename.replace('_demo.txt', '');
return [{ json: { account_id: accountId, transcript: $binary.data.toString() } }];

// Transforms extracted memo into Retell Agent Draft Spec
// See scripts/prompt_generator.py for full logic
const memo = JSON.parse($json.extracted);
const spec = generateAgentSpec(memo, 'v1');
return [{ json: { memo, spec, account_id: $json.account_id } }];

// Logs to task_log.json (mock Asana integration)
// In production: POST to Asana API
const task = {
  task_id: `CLARA-${Date.now()}`,
  account_id: $json.account_id,
  task_type: 'v1_generated',
  status: 'complete',
  created_at: new Date().toISOString()
};
return [{ json: task }];

// Runs LLM extraction on onboarding transcript
// Merges with v1 memo using deep_merge logic
// See scripts/merger.py for merge algorithm
const v1Memo = JSON.parse($json.v1_memo);
const onboardingData = $json.onboarding_extracted;
const [mergedMemo, changes] = deepMerge(v1Memo, onboardingData);
return [{ json: { merged_memo: mergedMemo, changes } }];
